select m.*, c.com_name from member m
left join company c on m.user_id = c.user_id
where m.user_id = #{userid}

SELECT COMPANY_NO AS companyNo
FROM COMPANY
WHERE USER_ID = #{userId}

select r.reg_date, r.img_description, r.is_paid, r.review_no, r.user_id,
r.company_no, r.product_no, r.rating, r.content, r.img_url, r.updated
from review r
where is_paid = 1 and product_no = #{productNo}
order by r.reg_date desc;

mapper.update:
update reservation
set
res_status = 'CONFIRM',
pay_date = #{payDate},
pay_no = #{payNo}
where res_no = #{resNo}

update inquiry_product
	set inquiry_ans = 1
where inquiry_no = #{inquiryNo}

update inquiry_product_answer
set 
	answer_contents = #{answerContents},
	ans_user_id = #{ansUserId}
where inquiry_no = #{inquiryNo}
